-- INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('i0052552-e0e1-11e8-b6c8-02f90e0f46f4', '3f49c30f-5d59-11e6-a130-5cc5d4d378cb', '活动更新时更新总费用总预算-计划转报销', '活动更新时更新总费用总预算', 'trigger', 'from django.db import connection\n# speaker_expense = 0\ntotal_expense = round(sum(instance.eventexpenses_set.filter(deleted=0, total_expense__isnull=False).values_list(\'total_expense\', flat=True)))\n# speaker_expense = round(sum(instance.eventspeakers_set.filter(deleted=0, speaker_expense__isnull=False).values_list(\n#     \'speaker_expense\', flat=True)))\nexpenses =total_expense\nif (instance.state.name == u\'save\'or instance.state.name == u\'rejected\'):\n    with connection.cursor() as c1:\n        sql = \'update events set text_5 = %s where id = %s\'\n        c1.execute(sql, (expenses, instance.id))\n\n        sql2 = \"update events set text_6 =concat(truncate(ABS({0} - event_budget)/event_budget *100,2),\'%\') where id = {1}\".format(\n            expenses, instance.id)\n        c1.execute(sql2)', '', '0', '1', '2019-06-24 11:08:42', '1', '2020-08-18 08:53:54', 'post_save_page', '1', 'custom', 'event_expense_turn', '1');
-- INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`) VALUES ('76e1a59a-f196-11e9-b9aa-0298a739dec0', '66036d1a-4643-49d5-b21a-0db9d60b0563', '参会率', '报告参会人数与计划参会人数比较', 'trigger', 'from django.db import connection\nfrom orion.common.user import get_current_user\n\ncur_user = get_current_user()\n\nif instance.event.record_type.name.endswith(\'report\'):\n    with connection.cursor() as cursor:\n        # 提交报告时测算字段\n        sql = \"\"\"\n                select count(id) from event_accounts where event_id = %s and deleted = 0 and record_type_id = \'c1491afa-18f4-4046-8e25-b62aed90eb77\'\n                \"\"\"\n\n        sql_child = \"\"\"\n                    select count(id) from event_accounts where event_id = %s and deleted = 0 and record_type_id = \'c1491afa-18f4-4046-8e25-b62aed90eb77\' and owner = %s\n                    \"\"\"\n\n        if instance.event.parent_id is None:\n            # plan\n            cursor.execute(sql, (instance.event.event_id,))\n            rows = cursor.fetchone()\n            if rows:\n                plan = rows[0]\n            else:\n                plan = 0\n            # report\n            cursor.execute(sql, (instance.event.id,))\n            rows = cursor.fetchone()\n            if rows:\n                report = rows[0]\n            else:\n                report = 0\n            if report:\n                sql_update = \"update events set text_7 =concat(truncate({0}/{1} *100,2),\'%\') where id = {2}\".format(report, plan, instance.event.id)\n                cursor.execute(sql_update)\n\n        else:\n            # 假设父子会议同步计划转报告，如果不同步存在漏洞\n            # plan\n            cursor.execute(sql_child, (instance.event.parent_id,cur_user.user_id))\n            rows = cursor.fetchone()\n            if rows:\n                plan = rows[0]\n            else:\n                plan = 0\n            # report\n            cursor.execute(sql_child, (instance.event.parent_id,cur_user.user_id))\n            rows = cursor.fetchone()\n            if rows:\n                report = rows[0]\n            else:\n                report = 0\n            if report:\n                sql_update = \"update events set text_7 =concat(truncate({0}/{1} *100,2),\'%\') where id = {2}\".format(report, plan, instance.event.id)\n                cursor.execute(sql_update)', '', '0', '1', '2019-10-18 11:08:42', '1', '2019-10-21 03:17:24', 'post_save', '1', 'custom', 'event_attendee_plan_report');
-- INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`) VALUES ('e49b1287-ec01-11e9-b9aa-0298a739dec0', '66036d1a-4643-49d5-b21a-0db9d60b0563', '测算参会人员数量', '测算参会人员数量', 'trigger', 'from django.db import connection\nfrom orion.common.user import get_current_user\n\ncur_user = get_current_user()\nwith connection.cursor() as cursor:\n    # 提交报告时测算字段\n    sql = \"\"\"\n            select count(id) from event_accounts where event_id = %s and deleted = 0 and record_type_id = \'c1491afa-18f4-4046-8e25-b62aed90eb77\'\n            \"\"\"\n\n    sql_child = \"\"\"\n                select count(id) from event_accounts where event_id = %s and deleted = 0 and record_type_id = \'c1491afa-18f4-4046-8e25-b62aed90eb77\' and owner = %s\n                \"\"\"\n    if instance.event.parent_id is None:\n        cursor.execute(sql, (instance.event.id,))\n    else:\n        cursor.execute(sql_child, (instance.event.parent_id, cur_user.user_id))\n    rows = cursor.fetchone()\n    if rows:\n        num_1 = rows[0]\n    else:\n        num_1 = 0\n    sql = \'update events set text_3 = %s where id = %s\'\n    cursor.execute(sql, (num_1, instance.event.id))', '', '0', '1', '2019-10-11 09:52:34', '1', '2020-06-09 09:35:09', 'post_save', '1', 'custom', 'attendee_num');
